 1	import { Button, EmptyStateActions } from '@patternfly/react-core';
 2	import React from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	import { Config } from '../../model/config';
 5	import { ContextSingleton } from '../../utils/context';
 6	import { Link } from '../../utils/url';
 7	
 8	export interface EmptyProps {
 9	  resetDefaultFilters?: (c?: Config) => void;
10	  clearFilters?: () => void;
11	  showMetrics?: () => void;
12	  showBuildInfo?: () => void;
13	  showConfigLimits?: () => void;
14	}
15	
16	export const SecondaryAction: React.FC<EmptyProps> = ({
17	  resetDefaultFilters,
18	  clearFilters,
19	  showMetrics,
20	  showBuildInfo,
21	  showConfigLimits
22	}) => {
23	  const { t } = useTranslation('plugin__netobserv-plugin');
24	  const flowCollectorK8SModel = ContextSingleton.getFlowCollectorK8SModel();
25	
26	  return (
27	    <>
28	      <EmptyStateActions>
29	        {flowCollectorK8SModel && (
30	          <Button
31	            variant="link"
32	            component={(props: React.FunctionComponent) => (
33	              <Link
34	                {...props}
35	                target="_blank"
36	                to={{
37	                  pathname: `/k8s/cluster/${flowCollectorK8SModel.apiGroup}~${flowCollectorK8SModel.apiVersion}~${flowCollectorK8SModel.kind}/cluster`
38	                }}
39	              />
40	            )}
41	          >
42	            {t('Show FlowCollector CR')}
43	          </Button>
44	        )}
45	        <Button
46	          variant="link"
47	          component={(props: React.FunctionComponent) => (
48	            <Link
49	              {...props}
50	              target="_blank"
51	              to={{ pathname: '/monitoring/dashboards/grafana-dashboard-netobserv-health' }}
52	            />
53	          )}
54	        >
55	          {t('Show health dashboard')}
56	        </Button>
57	        {clearFilters && (
58	          <Button id="clear-all-filters" onClick={() => clearFilters()} variant="link">
59	            {t('Clear all filters')}
60	          </Button>
61	        )}
62	        {resetDefaultFilters && (
63	          <Button id="reset-filters" onClick={() => resetDefaultFilters()} variant="link">
64	            {t('Reset defaults filters')}
65	          </Button>
66	        )}
67	        {showMetrics && (
68	          <Button id="show-metrics" onClick={() => showMetrics()} variant="link">
69	            {t('Show metrics')}
70	          </Button>
71	        )}
72	        {showBuildInfo && (
73	          <Button id="show-build-info" onClick={() => showBuildInfo()} variant="link">
74	            {t('Show build info')}
75	          </Button>
76	        )}
77	        {showConfigLimits && (
78	          <Button id="show-config-limits" onClick={() => showConfigLimits()} variant="link">
79	            {t('Show configuration limits')}
80	          </Button>
81	        )}
82	      </EmptyStateActions>
83	    </>
84	  );
85	};
86	
87	export default SecondaryAction;

